# CoAP Constants
COAP_VERSION = 1
COAP_PORT = 5683

# CoAP Types
CON = 0  # Confirmable
NON = 1  # Non-confirmable
ACK = 2  # Acknowledgement
RST = 3  # Reset

# CoAP Methods
EMPTY = 0
GET = 1
POST = 2
PUT = 3
DELETE = 4

# CoAP Response Codes
CONTENT = (2, 5)       # 2.05 Content
CHANGED = (2, 4)       # 2.04 Changed
BAD_REQUEST = (4, 0)   # 4.00 Bad Request
NOT_FOUND = (4, 4)     # 4.04 Not Found
METHOD_NOT_ALLOWED = (4, 5)  # 4.05 Method Not Allowed

# Content Format
CONTENT_FORMAT_PLAIN = 0
CONTENT_FORMAT_JSON = 50


class CoapOption:
    def __init__(self, number, value):
        self.number = number
        self.value = value


class CoapMessage:
    def __init__(self):
        self.version = COAP_VERSION
        self.type = CON
        self.token_length = 0
        self.code_class = 0
        self.code_detail = 0
        self.message_id = 0
        self.token = b''
        self.options = []
        self.payload = b''

    @property
    def uri_path(self):
        """Extract URI path from options (option number 11)."""
        parts = []
        for opt in self.options:
            if opt.number == 11:
                parts.append(opt.value.decode('utf-8') if isinstance(opt.value, bytes) else opt.value)
        return '/' + '/'.join(parts) if parts else '/'

    @staticmethod
    def parse(data):
        """Parse raw bytes into a CoapMessage."""
        msg = CoapMessage()
        if len(data) < 4:
            return None

        first_byte = data[0]
        msg.version = (first_byte >> 6) & 0x03
        msg.type = (first_byte >> 4) & 0x03
        msg.token_length = first_byte & 0x0F

        second_byte = data[1]
        msg.code_class = (second_byte >> 5) & 0x07
        msg.code_detail = second_byte & 0x1F

        msg.message_id = (data[2] << 8) | data[3]

        offset = 4

        # Parse token
        if msg.token_length > 0:
            msg.token = data[offset:offset + msg.token_length]
            offset += msg.token_length

        # Parse options
        prev_option_number = 0
        while offset < len(data):
            if data[offset] == 0xFF:
                # Payload marker
                offset += 1
                msg.payload = data[offset:]
                break

            option_delta = (data[offset] >> 4) & 0x0F
            option_length = data[offset] & 0x0F
            offset += 1

            # Extended delta
            if option_delta == 13:
                option_delta = data[offset] + 13
                offset += 1
            elif option_delta == 14:
                option_delta = ((data[offset] << 8) | data[offset + 1]) + 269
                offset += 2

            # Extended length
            if option_length == 13:
                option_length = data[offset] + 13
                offset += 1
            elif option_length == 14:
                option_length = ((data[offset] << 8) | data[offset + 1]) + 269
                offset += 2

            option_number = prev_option_number + option_delta
            option_value = data[offset:offset + option_length]
            offset += option_length

            msg.options.append(CoapOption(option_number, option_value))
            prev_option_number = option_number

        return msg

    def to_bytes(self):
        """Serialize CoapMessage to bytes."""
        buf = bytearray()

        first_byte = ((self.version & 0x03) << 6) | ((self.type & 0x03) << 4) | (self.token_length & 0x0F)
        buf.append(first_byte)

        second_byte = ((self.code_class & 0x07) << 5) | (self.code_detail & 0x1F)
        buf.append(second_byte)

        buf.append((self.message_id >> 8) & 0xFF)
        buf.append(self.message_id & 0xFF)

        # Token
        if self.token_length > 0:
            buf.extend(self.token)

        # Options (sorted by number)
        self.options.sort(key=lambda o: o.number)
        prev_number = 0
        for opt in self.options:
            delta = opt.number - prev_number
            value = opt.value if isinstance(opt.value, (bytes, bytearray)) else opt.value.encode('utf-8')
            length = len(value)

            option_byte = 0

            # Encode delta
            if delta < 13:
                option_byte |= (delta << 4)
                delta_ext = b''
            elif delta < 269:
                option_byte |= (13 << 4)
                delta_ext = bytes([delta - 13])
            else:
                option_byte |= (14 << 4)
                d = delta - 269
                delta_ext = bytes([(d >> 8) & 0xFF, d & 0xFF])

            # Encode length
            if length < 13:
                option_byte |= length
                length_ext = b''
            elif length < 269:
                option_byte |= 13
                length_ext = bytes([length - 13])
            else:
                option_byte |= 14
                l = length - 269
                length_ext = bytes([(l >> 8) & 0xFF, l & 0xFF])

            buf.append(option_byte)
            buf.extend(delta_ext)
            buf.extend(length_ext)
            buf.extend(value)

            prev_number = opt.number

        # Payload
        if self.payload:
            buf.append(0xFF)
            if isinstance(self.payload, str):
                buf.extend(self.payload.encode('utf-8'))
            else:
                buf.extend(self.payload)

        return bytes(buf)


class DeviceState:
    """Holds current device sensor readings and actuator states."""

    def __init__(self):
        self.light_state = False
        self.light_brightness = 0
        self._temp_sensor = None

        # Try to initialize onboard temperature sensor (RP2040/ESP32)
        try:
            self._temp_sensor = machine.ADC(4)  # RP2040 internal temp
        except Exception:
            pass

    def read_temperature(self):
        """Read temperature from sensor or return simulated value."""
        if self._temp_sensor:
            try:
                reading = self._temp_sensor.read_u16()
                voltage = reading * 3.3 / 65535
                temperature = 27 - (voltage - 0.706) / 0.001721
                return round(temperature, 1)
            except Exception:
                pass
        # Simulated temperature for testing
        import urandom
        base_temp = 22.0
        variation = (urandom.getrandbits(8) - 128) / 100.0
        return round(base_temp + variation, 1)

    def set_light(self, state, brightness=None):
        """Set light actuator state."""
        self.light_state = bool(state)
        if brightness is not None:
            self.light_brightness = max(0, min(100, int(brightness)))

        # Drive actual GPIO if available
        try:
            led = machine.Pin(2, machine.Pin.OUT)  # Common onboard LED pin
            led.value(1 if self.light_state else 0)
        except Exception:
            pass

    def get_light_status(self):
        return {
            "state": "on" if self.light_state else "off",
            "brightness": self.light_brightness
        }


class CoapResource:
    """Represents a CoAP resource with handlers."""

    def __init__(self, path, get_handler=None, put_handler=None):
        self.path = path
        self.get_handler = get_handler
        self.put_handler = put_handler


class CoapServer:
    """Lightweight CoAP server for MicroPython IoT devices."""

    def __init__(self, host='0.0.0.0', port=COAP_PORT):
        self.host = host
        self.port = port
        self.resources = {}
        self.sock = None
        self.running = False
        self.device = DeviceState()
        self._register_default_resources()

    def _register_default_resources(self):
        """Register built-in device resources."""

        # /sensors/temp - GET temperature reading
        self.add_resource(
            '/sensors/temp',
            get_handler=self._handle_temp_get
        )

        # /actuators/light - GET status, PUT to control
        self.add_resource(
            '/actuators/light',
            get_handler=self._handle_light_get,
            put_handler=self._handle_light_put
        )

        # /.well-known/core - CoAP resource discovery
        self.add_resource(
            '/.well-known/core',
            get_handler=self._handle_discovery
        )

    def add_resource(self, path, get_handler=None, put_handler=None):
        """Register a CoAP resource with its handlers."""
        self.resources[path] = CoapResource(path, get_handler, put_handler)

    def _handle_temp_get(self, request):
        """Handle GET /sensors/temp"""
        temp = self.device.read_temperature()
        payload = json.dumps({
            "temperature": temp,
            "unit": "celsius",
            "timestamp": time.time()
        })
        return CONTENT, payload, CONTENT_FORMAT_JSON

    def _handle_light_get(self, request):
        """Handle GET /actuators/light"""
        status = self.device.get_light_status()
        payload = json.dumps(status)
        return CONTENT, payload, CONTENT_FORMAT_JSON

    def _handle_light_put(self, request):
        """Handle PUT /actuators/light"""
        try:
            if request.payload:
                payload_str = request.payload.decode('utf-8') if isinstance(request.payload, bytes) else request.payload
                data = json.loads(payload_str)

                state = data.get('state', None)
                brightness = data.get('brightness', None)

                if state is not None:
                    if isinstance(state, str):
                        state = state.lower() in ('on', 'true', '1')
                    self.device.set_light(state, brightness)
                elif brightness is not None:
                    self.device.set_light(self.device.light_state, brightness)
                else:
                    return BAD_REQUEST, "Missing 'state' or 'brightness'", CONTENT_FORMAT_PLAIN

                response_payload = json.dumps(self.device.get_light_status())
                return CHANGED, response_payload, CONTENT_FORMAT_JSON
            else:
                return BAD_REQUEST, "Empty payload", CONTENT_FORMAT_PLAIN
        except (ValueError, KeyError) as e:
            return BAD_REQUEST, "Invalid JSON: {}".format(str(e)), CONTENT_FORMAT_PLAIN

    def _handle_discovery(self, request):
        """Handle GET /.well-known/core (CoRE Link Format)"""
        links = []
        for path, resource in self.resources.items():
            if path == '/.well-known/core':
                continue
            methods = []
            if resource.get_handler:
                methods.append('GET')
            if resource.put_handler:
                methods.append('PUT')
            link = '<{}>;ct=50;methods="{}"'.format(path, ','.join(methods))
            links.append(link)
        payload = ','.join(links)
        return CONTENT, payload, 40  # application/link-format

    def _build_response(self, request, code, payload='', content_format=None):
        """Build a CoAP response message."""
        resp = CoapMessage()
        resp.version = COAP_VERSION
        resp.type = ACK if request.type == CON else NON
        resp.message_id = request.message_id
        resp.token_length = request.token_length
        resp.token = request.token
        resp.code_class = code[0]
        resp.code_detail = code[1]

        # Add content format option if specified
        if content_format is not None and payload:
            cf_bytes = bytearray()
            if content_format < 256:
                cf_bytes.append(content_format)
            else:
                cf_bytes.append((content_format >> 8) & 0xFF)
                cf_bytes.append(content_format & 0xFF)
            resp.options.append(CoapOption(12, bytes(cf_bytes)))

        if payload:
            resp.payload = payload.encode('utf-8') if isinstance(payload, str) else payload

        return resp

    def _dispatch(self, request):
        """Route request to appropriate resource handler."""
        uri = request.uri_path
        method_code = request.code_detail  # GET=1, PUT=3

        print("[CoAP] {} {} from mid={}".format(
            {1: 'GET', 2: 'POST', 3: 'PUT', 4: 'DELETE'}.get(method_code, 'UNKNOWN'),
            uri,
            request.message_id
        ))

        resource = self.resources.get(uri)

        if resource is None:
            return self._build_response(request, NOT_FOUND, "Resource not found")

        handler = None
        if method_code == GET and resource.get_handler:
            handler = resource.get_handler
        elif method_code == PUT and resource.put_handler:
            handler = resource.put_handler

        if handler is None:
            return self._build_response(request, METHOD_NOT_ALLOWED, "Method not allowed")

        try:
            code, payload, content_format = handler(request)
            return self._build_response(request, code, payload, content_format)
        except Exception as e:
            print("[CoAP] Handler error: {}".format(e))
            return self._build_response(request, BAD_REQUEST, "Server error: {}".format(str(e)))

    def start(self):
        """Start the CoAP server (blocking)."""
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.sock.bind((self.host, self.port))
        self.sock.settimeout(1.0)  # Allow periodic checks
        self.running = True

        print("[CoAP] Server started on {}:{}".format(self.host, self.port))
        print("[CoAP] Resources:")
        for path in self.resources:
            res = self.resources[path]
            methods = []
            if res.get_handler:
                methods.append('GET')
            if res.put_handler:
                methods.append('PUT')
            print("  {} [{}]".format(path, ', '.join(methods)))

        while self.running:
            try:
                data, addr = self.sock.recvfrom(256)  # Small buffer for constrained devices
                request = CoapMessage.parse(data)

                if request is None:
                    print("[CoAP] Malformed packet from {}".format(addr))
                    continue

                if request.version != COAP_VERSION:
                    print("[CoAP] Unsupported version from {}".format(addr))
                    continue

                # Only process requests (code class 0, detail > 0)
                if request.code_class == 0 and request.code_detail > 0:
                    response = self._dispatch(request)
                    response_bytes = response.to_bytes()
                    self.sock.sendto(response_bytes, addr)
                elif request.code_class == 0 and request.code_detail == 0:
                    # Empty message (ping) - respond with RST
                    resp = CoapMessage()
                    resp.type = RST
                    resp.message_id = request.message_id
                    self.sock.sendto(resp.to_bytes(), addr)

            except OSError as e:
                # Timeout - just loop, allows checking self.running
                if e.args[0] == 110 or e.args[0] == 11:  # ETIMEDOUT / EAGAIN
                    continue
                print("[CoAP] Socket error: {}".format(e))
            except Exception as e:
                print("[CoAP] Error: {}".format(e))

        self.sock.close()
        print("[CoAP] Server stopped")

    def stop(self):
        """Stop the CoAP server."""
        self.running = False


def connect_wifi(ssid, password, timeout=15):
    """Connect to WiFi network (ESP32/ESP8266)."""
    try:
        import network
        wlan = network.WLAN(network.STA_IF)
        wlan.active(True)

        if wlan.isconnected():
            print("[WiFi] Already connected: {}".format(wlan.ifconfig()[0]))
            return True

        print("[WiFi] Connecting to {}...".format(ssid))
        wlan.connect(ssid, password)

        start = time.time()
        while not wlan.isconnected():
            if time.time() - start > timeout:
                print("[WiFi] Connection timeout")
                return False
            time.sleep(0.5)

        print("[WiFi] Connected: {}".format(wlan.ifconfig()[0]))
        return True
    except ImportError:
        print("[WiFi] network module not available (not on ESP32/ESP8266?)")
        return True  # Assume network is available (e.g., Linux MicroPython)


