def custom_humidity_get(request):
    """Example custom resource handler for humidity sensor."""
    import urandom
    humidity = 45.0 + (urandom.getrandbits(8) - 128) / 50.0
    payload = json.dumps({
        "humidity": round(humidity, 1),
        "unit": "percent",
        "timestamp": time.time()
    })
    return CONTENT, payload, CONTENT_FORMAT_JSON


def custom_device_info_get(request):
    """Device info resource."""
    import sys
    payload = json.dumps({
        "platform": sys.platform,
        "version": sys.version,
        "mem_free": getattr(machine, 'mem_free', lambda: 'N/A')() if hasattr(machine, 'mem_free') else 'N/A',
        "freq_mhz": machine.freq() // 1_000_000 if hasattr(machine, 'freq') else 'N/A'
    })
    return CONTENT, payload, CONTENT_FORMAT_JSON


